  1→<?php
  2→
  3→namespace App\Service;
  4→
  5→use App\Models\DailyReport;
  6→use App\Models\DailyReportAiRoom;
  7→use App\Models\DailyReportAiTunnel;
  8→use App\Models\DailyReportWeeklySummary;
  9→use App\Service\Traits\TService;
 10→use Carbon\Carbon;
 11→use Illuminate\Support\Facades\DB;
 12→use Illuminate\Support\Facades\Log;
 13→
 14→class WeeklySummaryService
 15→{
 16→    use TService;
 17→
 18→    /**
 19→     * 计算 ISO 周边界（周一~周日）.
 20→     *
 21→     * @return array{week_start: string, week_end: string}
 22→     */
 23→    public function getWeekBounds(string $date): array
 24→    {
 25→        $carbon = Carbon::parse($date);
 26→        $weekStart = $carbon->copy()->startOfWeek(Carbon::MONDAY)->toDateString();
 27→        $weekEnd = $carbon->copy()->endOfWeek(Carbon::SUNDAY)->toDateString();
 28→
 29→        return ['week_start' => $weekStart, 'week_end' => $weekEnd];
 30→    }
 31→
 32→    /**
 33→     * 从该用户本周已提交的日报中，取 reporter_ids 和 cc_ids 的并集.
 34→     *
 35→     * @return array{0: string, 1: string} [reporter_ids, cc_ids]
 36→     */
 37→    public function resolveReporterAndCcIds(int $sfuserId, string $weekStart, string $weekEnd): array
 38→    {
 39→        $reports = DailyReport::where('sfuser_id', $sfuserId)
 40→            ->where('report_date', '>=', $weekStart)
 41→            ->where('report_date', '<=', $weekEnd)
 42→            ->where('status', DailyReport::STATUS_COMMITTED)
 43→            ->select(['reporter_ids', 'cc_ids'])
 44→            ->get();
 45→
 46→        $reporterIds = [];
 47→        $ccIds = [];
 48→        foreach ($reports as $report) {
 49→            foreach (array_filter(explode(',', $report->reporter_ids)) as $id) {
 50→                $reporterIds[(int)$id] = true;
 51→            }
 52→            foreach (array_filter(explode(',', $report->cc_ids)) as $id) {
 53→                $ccIds[(int)$id] = true;
 54→            }
 55→        }
 56→
 57→        return [
 58→            implode(',', array_keys($reporterIds)),
 59→            implode(',', array_keys($ccIds)),
 60→        ];
 61→    }
 62→
 63→    /**
 64→     * 仅查找 Room（不创建），优先精确匹配 project_name，再模糊匹配 aliases.
 65→     */
 66→    public function findRoomByName(string $projectName): ?int
 67→    {
 68→        $projectName = trim($projectName);
 69→        if (empty($projectName)) {
 70→            return null;
 71→        }
 72→
 73→        // 精确匹配 project_name
 74→        $room = DailyReportAiRoom::where('project_name', $projectName)
 75→            ->where('status', DailyReportAiRoom::STATUS_ACTIVE)
 76→            ->first();
 77→        if ($room) {
 78→            return $room->id;
 79→        }
 80→
 81→        // 模糊匹配 aliases
 82→        $aliasRoom = DailyReportAiRoom::where('status', DailyReportAiRoom::STATUS_ACTIVE)
 83→            ->whereRaw('JSON_CONTAINS(aliases, ?)', [json_encode($projectName)])
 84→            ->first();
 85→
 86→        return $aliasRoom?->id;
 87→    }
 88→
 89→    /**
 90→     * 查找或创建 Room，优先精确匹配 project_name，再模糊匹配 aliases.
 91→     */
 92→    public function findOrCreateRoom(string $projectName): int
 93→    {
 94→        $projectName = trim($projectName);
 95→        if (empty($projectName)) {
 96→            return 0;
 97→        }
 98→
 99→        // 精确匹配 project_name
100→        $room = DailyReportAiRoom::where('project_name', $projectName)
101→            ->where('status', DailyReportAiRoom::STATUS_ACTIVE)
102→            ->first();
103→        if ($room) {
104→            return $room->id;
105→        }
106→
107→        // 模糊匹配 aliases（用 MySQL JSON_CONTAINS 代替全表扫描）
108→        $aliasRoom = DailyReportAiRoom::where('status', DailyReportAiRoom::STATUS_ACTIVE)
109→            ->whereRaw('JSON_CONTAINS(aliases, ?)', [json_encode($projectName)])
110→            ->first();
111→        if ($aliasRoom) {
112→            return $aliasRoom->id;
113→        }
114→
115→        // 未找到，用 firstOrCreate 防止并发重复（配合 unique 约束）
116→        try {
117→            $newRoom = DailyReportAiRoom::firstOrCreate(
118→                ['project_name' => $projectName],
119→                ['aliases' => [], 'status' => DailyReportAiRoom::STATUS_ACTIVE],
120→            );
121→
122→            if ($newRoom->wasRecentlyCreated) {
123→                Log::info('[lbl][0423-周摘要][Room] 新建项目', [
124→                    'room_id' => $newRoom->id,
125→                    'project_name' => $projectName,
126→                ]);
127→            }
128→
129→            return $newRoom->id;
130→        } catch (\Throwable $e) {
131→            // 唯一键冲突兜底：再查一次
132→            Log::warning('[lbl][0423-周摘要][Room] 创建冲突，重新查询', [
133→                'project_name' => $projectName,
134→                'error' => $e->getMessage(),
135→            ]);
136→            $existing = DailyReportAiRoom::where('project_name', $projectName)->first();
137→
138→            return $existing ? $existing->id : 0;
139→        }
140→    }
141→
142→    /**
143→     * 保存人员-项目关联（Tunnel）.
144→     */
145→    public function saveTunnel(int $roomId, int $sfuserId, string $weekStart): void
146→    {
147→        if ($roomId <= 0) {
148→            return;
149→        }
150→
151→        DailyReportAiTunnel::insertOrIgnore([
152→            'room_id' => $roomId,
153→            'sfuser_id' => $sfuserId,
154→            'week_start' => $weekStart,
155→            'created_at' => now(),
156→        ]);
157→    }
158→
159→    /**
160→     * 保存周摘要（upsert）.
161→     *
162→     * @return array{id: int, created: bool}
163→     */
164→    public function saveSummary(array $data): array
165→    {
166→        return DB::transaction(function () use ($data) {
167→            $sfuserId = $data['sfuser_id'];
168→            $weekStart = $data['week_start'];
169→
170→            // 加排他锁防止并发 upsert 唯一键冲突
171→            $existing = DailyReportWeeklySummary::where('sfuser_id', $sfuserId)
172→                ->where('week_start', $weekStart)
173→                ->lockForUpdate()
174→                ->first();
175→
176→            $summaryData = [
177→                'sfuser_id' => $sfuserId,
178→                'week_start' => $weekStart,
179→                'week_end' => $data['week_end'],
180→                'reporter_ids' => $data['reporter_ids'] ?? '',
181→                'cc_ids' => $data['cc_ids'] ?? '',
182→                'content' => $data['content'],
183→                'token' => $data['token'] ?? '',
184→                'submit_days' => $data['submit_days'] ?? 0,
185→                'total_chars' => $data['total_chars'] ?? 0,
186→            ];
187→
188→            $created = false;
189→            if ($existing) {
190→                $existing->update($summaryData);
191→                $summaryId = $existing->id;
192→            } else {
193→                try {
194→                    $summary = DailyReportWeeklySummary::create($summaryData);
195→                    $summaryId = $summary->id;
196→                    $created = true;
197→                } catch (\Illuminate\Database\QueryException $e) {
198→                    // 唯一键冲突兜底：并发创建时另一个事务已插入
199→                    $existing = DailyReportWeeklySummary::where('sfuser_id', $sfuserId)
200→                        ->where('week_start', $weekStart)
201→                        ->first();
202→                    $existing->update($summaryData);
203→                    $summaryId = $existing->id;
204→                }
205→            }
206→
207→            // 替换来源日报关联
208→            $reportIds = $data['report_ids'] ?? [];
209→            if (!empty($reportIds)) {
210→                DB::table('daily_report_weekly_summary_report_ids')
211→                    ->where('summary_id', $summaryId)
212→                    ->delete();
213→
214→                $rows = array_map(fn ($rid) => [
215→                    'summary_id' => $summaryId,
216→                    'report_id' => $rid,
217→                ], $reportIds);
218→
219→                DB::table('daily_report_weekly_summary_report_ids')->insert($rows);
220→            }
221→
222→            return ['id' => $summaryId, 'created' => $created];
223→        });
224→    }
225→}
